using namespace std;

class Solution {
public:
    string minWindow(string s, string t) {
        if (t.empty()) return "";
        if (s.size() < t.size()) return "";

        vector<int> count_t(256, 0);
        vector<int> count_s(256, 0);
        int required = 0;

        for (char c : t) {
            if (count_t[c] == 0) {
                required++;
            }
            count_t[c]++;
        }

        int have = 0;
        int min_len = INT_MAX;
        string min_window;
        int left = 0;

        for (int right = 0; right < s.size(); right++) {
            char c = s[right];
            if (count_t[c] > 0) {
                count_s[c]++;
                if (count_s[c] == count_t[c]) {
                    have++;
                }
            }

            while (have == required) {
                int current_len = right - left + 1;
                if (current_len < min_len) {
                    min_len = current_len;
                    min_window = s.substr(left, current_len);
                }

                char left_c = s[left];
                if (count_t[left_c] > 0) {
                    if (count_s[left_c] == count_t[left_c]) {
                        have--;
                    }
                    count_s[left_c]--;
                }
                left++;
            }
        }

        return min_window;
    }
};

